import test from "node:test";
import assert from "node:assert/strict";

import { SessionPump } from "../src/session-pump.mjs";
import { ConnectionService } from "../src/connection-service.mjs";

function deferred() {
  let resolve;
  let reject;
  const promise = new Promise((onResolve, onReject) => {
    resolve = onResolve;
    reject = onReject;
  });
  return { promise, resolve, reject };
}

test("a superseded receive cannot publish or retire the replacement generation", async () => {
  const oldReceive = deferred();
  const newReceive = deferred();
  const messages = [];
  const statuses = [];
  let oldReads = 0;

  const oldTransport = {
    name: "old",
    async open() {},
    receive() {
      oldReads += 1;
      return oldReads === 1 ? oldReceive.promise : Promise.resolve(null);
    }
  };
  const newTransport = {
    name: "new",
    async open() {},
    receive() {
      return newReceive.promise;
    }
  };

  const pump = new SessionPump({
    onMessage: async (message) => messages.push(message),
    onStatus: (status) => statuses.push(status)
  });

  const oldRun = pump.replace(oldTransport);
  await Promise.resolve();
  const newRun = pump.replace(newTransport);
  await Promise.resolve();

  oldReceive.resolve({ source: "old", value: "late" });
  await oldRun;

  assert.deepEqual(messages, []);
  assert.equal(pump.currentTransport(), newTransport);
  assert.equal(statuses.some((status) => status.kind === "offline" && status.name === "old"), false);

  newReceive.resolve(null);
  await newRun;
  assert.equal(pump.currentTransport(), null);
});

test("service-level handover keeps the replacement visible after old EOF", async () => {
  const oldReceive = deferred();
  const newReceive = deferred();
  const service = new ConnectionService();
  const oldTransport = { name: "socket-a", async open() {}, receive: () => oldReceive.promise };
  const newTransport = { name: "socket-b", async open() {}, receive: () => newReceive.promise };

  const oldRun = service.connect(oldTransport, null);
  await Promise.resolve();
  const newRun = service.connect(newTransport, null);
  await Promise.resolve();
  oldReceive.resolve(null);
  await oldRun;

  assert.equal(service.currentName(), "socket-b");
  newReceive.resolve(null);
  await newRun;
});
